mapper.select:
SELECT EXISTS (
    SELECT 1 FROM tbl_bookmark
    WHERE member_id = #{memberId}
      AND target_type = #{targetType}
      AND target_id = #{targetId}
)

mapper.delete:
DELETE FROM tbl_bookmark
WHERE member_id = #{memberId}
  AND target_type = #{targetType}
  AND target_id = #{targetId}
